return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var size = 1;
    if (progress >= 0.3 && progress < 0.6) size = 2;
    else if (progress >= 0.6) size = 3;

    var midX = W / 2;
    var midY = H / 2 - 15;
    var cubeSize = 18;
    var w = cubeSize * 0.866;
    var h = cubeSize * 0.5;

    function drawCube(x, y, colorTop, colorLeft, colorRight) {
      // Top face
      ctx.fillStyle = colorTop;
      ctx.beginPath();
      ctx.moveTo(x, y - cubeSize);
      ctx.lineTo(x + w, y - h);
      ctx.lineTo(x, y);
      ctx.lineTo(x - w, y - h);
      ctx.closePath();
      ctx.fill();
      ctx.strokeStyle = '#1F2937';
      ctx.lineWidth = 0.5;
      ctx.stroke();

      // Left face
      ctx.fillStyle = colorLeft;
      ctx.beginPath();
      ctx.moveTo(x - w, y - h);
      ctx.lineTo(x, y);
      ctx.lineTo(x, y + cubeSize);
      ctx.lineTo(x - w, y + cubeSize - h);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();

      // Right face
      ctx.fillStyle = colorRight;
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x + w, y - h);
      ctx.lineTo(x + w, y + cubeSize - h);
      ctx.lineTo(x, y + cubeSize);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();
    }

    // Colors based on size
    var colTop = '#60A5FA', colLeft = '#3B82F6', colRight = '#1D4ED8';
    if (size === 2) {
      colTop = '#34D399'; colLeft = '#10B981'; colRight = '#047857';
    } else if (size === 3) {
      colTop = '#FBBF24'; colLeft = '#F59E0B'; colRight = '#B45309';
    }

    // Stacking blocks in isometric projection back-to-front
    // dz is height index (0 to size-1)
    // dx, dy are horizontal indices (0 to size-1)
    for (var dz = 0; dz < size; dz++) {
      for (var dy = 0; dy < size; dy++) {
        for (var dx = 0; dx < size; dx++) {
          // Screen position calculation
          // To center the entire stack:
          var stackOffsetX = (dx - dy) * w;
          var stackOffsetY = (dx + dy) * h - dz * cubeSize;

          // Center adjustment shift
          var shiftX = midX;
          var shiftY = midY + (size - 1) * h * 0.2;

          drawCube(shiftX + stackOffsetX, shiftY + stackOffsetY, colTop, colLeft, colRight);
        }
      }
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (size === 1) {
      ctx.fillText('1³ = 1 × 1 × 1 = 1', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('1 block total (1x1x1)', W / 2, H - 22);
    } else if (size === 2) {
      ctx.fillStyle = '#34D399';
      ctx.fillText('2³ = 2 × 2 × 2 = 8', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('2 × 2 × 2 grid. Total = 8 blocks.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('3³ = 3 × 3 × 3 = 27', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('3 × 3 × 3 grid. Total = 27 blocks.', W / 2, H - 22);
    }
  }
};
